record.field:
{
  "type": "object",
  "properties": {
    "vat": {
      "type": "string",
      "description": "DNI o CUIT ingresado por el cliente. Puede incluir guiones o espacios."
    }
  },
  "required": ["vat"]
}

{
  "type": "object",
  "properties": {
    "limit": {
      "type": "integer",
      "description": "Cantidad máxima de facturas a mostrar. Default: 5",
      "default": 5
    }
  },
  "required": []
}

{
  "type": "object",
  "properties": {
    "invoice_id": {
      "type": "integer",
      "description": "ID de la factura específica a pagar. Si no se especifica, usa la más antigua vencida."
    }
  },
  "required": []
}

{
  "type": "object",
  "properties": {
    "subject": {
      "type": "string",
      "description": "Título del reclamo o problema reportado"
    },
    "description": {
      "type": "string",
      "description": "Descripción detallada del problema"
    },
    "ticket_type": {
      "type": "string",
      "enum": ["technical", "billing", "general"],
      "description": "Tipo de reclamo"
    }
  },
  "required": ["subject"]
}

{
  "type": "object",
  "properties": {
    "limit": {
      "type": "integer",
      "description": "Cantidad máxima de tickets a mostrar. Default: 5",
      "default": 5
    }
  },
  "required": []
}

{
  "type": "object",
  "properties": {
    "contract_id": {
      "type": "integer",
      "description": "ID del contrato a suspender. Si no se especifica, suspende el activo."
    },
    "reason": {
      "type": "string",
      "description": "Motivo de la suspensión"
    }
  },
  "required": []
}

{
  "type": "object",
  "properties": {
    "contract_id": {
      "type": "integer",
      "description": "ID del contrato a activar. Si no se especifica, activa el suspendido."
    }
  },
  "required": []
}

{
  "type": "object",
  "properties": {
    "name": {
      "type": "string",
      "description": "Nombre del lead o descripción del interés"
    },
    "description": {
      "type": "string",
      "description": "Detalle de lo que está buscando el prospecto"
    }
  },
  "required": []
}

{
  "type": "object",
  "properties": {
    "interest_level": {
      "type": "string",
      "enum": ["hot", "warm", "cold"],
      "description": "Nivel de interés: hot=muy interesado, warm=interesado, cold=baja prioridad"
    },
    "notes": {
      "type": "string",
      "description": "Notas adicionales sobre el prospecto"
    }
  },
  "required": ["interest_level"]
}
